&lt;p&gt;&lt;strong&gt;What you&#39;ll do:&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot; data-ccp-parastyle-defn=&quot;{&amp;quot;ObjectId&amp;quot;:&amp;quot;7101eae0-c74b-4390-b787-96da9e19e035|152&amp;quot;,&amp;quot;ClassId&amp;quot;:1073872969,&amp;quot;Properties&amp;quot;:[469775450,&amp;quot;Default&amp;quot;,201340122,&amp;quot;2&amp;quot;,134233614,&amp;quot;true&amp;quot;,469778129,&amp;quot;Default&amp;quot;,335572020,&amp;quot;1&amp;quot;,469777841,&amp;quot;EINA04-LIGHT&amp;quot;,469777842,&amp;quot;EINA04-LIGHT&amp;quot;,469777843,&amp;quot;Calibri&amp;quot;,469777844,&amp;quot;EINA04-LIGHT&amp;quot;,469769226,&amp;quot;EINA04-LIGHT,Calibri&amp;quot;,335551500,&amp;quot;0&amp;quot;,268442635,&amp;quot;24&amp;quot;,335559704,&amp;quot;1025&amp;quot;,335559705,&amp;quot;1033&amp;quot;,335551547,&amp;quot;1033&amp;quot;]}&quot;&gt;&lt;strong&gt;Own and ship a meaningful project, end-to-end&lt;/strong&gt;. We believe strongly in ownership at The Trade Desk, and we are committed to you having something &lt;/span&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt;substantial&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; to show for your time here that will make a positive Impact for the team&lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;201341983&amp;quot;:2,&amp;quot;335551550&amp;quot;:6,&amp;quot;335551620&amp;quot;:6,&amp;quot;335559740&amp;quot;:241}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt;&lt;strong&gt;Receive close, one-on-one mentorship&lt;/strong&gt; from an experienced software engineer&lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;201341983&amp;quot;:2,&amp;quot;335551550&amp;quot;:6,&amp;quot;335551620&amp;quot;:6,&amp;quot;335559740&amp;quot;:241}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt;&lt;strong&gt;Collaborate with a globally connected team&lt;/strong&gt; of engineers, Interns &amp;amp; other &lt;/span&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt;teams&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; and departments in cities across the world&lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;201341983&amp;quot;:2,&amp;quot;335551550&amp;quot;:6,&amp;quot;335551620&amp;quot;:6,&amp;quot;335559740&amp;quot;:241}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;strong&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt;Work with &lt;/span&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt;new technologies&lt;/span&gt;&lt;/strong&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; across a wide spectrum of computer science, including distributed systems, petabyte-scale data processing, machine learning/AI, and UI/UX&lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;Default&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;201341983&amp;quot;:2,&amp;quot;335551550&amp;quot;:6,&amp;quot;335551620&amp;quot;:6,&amp;quot;335559740&amp;quot;:241}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&amp;nbsp;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Who you are:&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot; data-ccp-charstyle-defn=&quot;{&amp;quot;ObjectId&amp;quot;:&amp;quot;c641e779-56bc-4e6c-a8e2-18ec74ca2a29|189&amp;quot;,&amp;quot;ClassId&amp;quot;:1073872969,&amp;quot;Properties&amp;quot;:[201342447,&amp;quot;5&amp;quot;,201342448,&amp;quot;3&amp;quot;,469777841,&amp;quot;Akkurat&amp;quot;,469777842,&amp;quot;&amp;quot;,469777843,&amp;quot;ＭＳ 明朝&amp;quot;,469777844,&amp;quot;Akkurat&amp;quot;,469769226,&amp;quot;Akkurat,ＭＳ 明朝&amp;quot;,268442635,&amp;quot;24&amp;quot;,469775450,&amp;quot;normaltextrun&amp;quot;,201340122,&amp;quot;1&amp;quot;,134233614,&amp;quot;true&amp;quot;,469778129,&amp;quot;normaltextrun&amp;quot;,335572020,&amp;quot;1&amp;quot;,469778324,&amp;quot;Default Paragraph Font&amp;quot;]}&quot;&gt;You might be a great fit for a Software Engineer internship at The Trade Desk if:&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;strong&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;eop&quot; data-ccp-charstyle-defn=&quot;{&amp;quot;ObjectId&amp;quot;:&amp;quot;c641e779-56bc-4e6c-a8e2-18ec74ca2a29|190&amp;quot;,&amp;quot;ClassId&amp;quot;:1073872969,&amp;quot;Properties&amp;quot;:[201342447,&amp;quot;5&amp;quot;,201342448,&amp;quot;3&amp;quot;,469777841,&amp;quot;Akkurat&amp;quot;,469777842,&amp;quot;&amp;quot;,469777843,&amp;quot;ＭＳ 明朝&amp;quot;,469777844,&amp;quot;Akkurat&amp;quot;,469769226,&amp;quot;Akkurat,ＭＳ 明朝&amp;quot;,268442635,&amp;quot;24&amp;quot;,469775450,&amp;quot;eop&amp;quot;,201340122,&amp;quot;1&amp;quot;,134233614,&amp;quot;true&amp;quot;,469778129,&amp;quot;eop&amp;quot;,335572020,&amp;quot;1&amp;quot;,469778324,&amp;quot;Default Paragraph Font&amp;quot;]}&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span data-ccp-props=&quot;{&amp;quot;134233117&amp;quot;:false,&amp;quot;134233118&amp;quot;:false,&amp;quot;335559738&amp;quot;:0,&amp;quot;335559739&amp;quot;:0}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;You are fluent in one or more modern programming languages, eg, Javascript, Python, Java, PHP, C and C++, SQL&lt;/li&gt;
&lt;li&gt;Have a firm grasp on basic data structures and algorithmic techniques &lt;/li&gt;
&lt;li&gt;You are comfortable working on an agile, distributed team spanning multiple time zones and continents.&lt;/li&gt;
&lt;li&gt;Capable of communicating effectively within a collaborative, complex, and highly technical team environment.&lt;/li&gt;
&lt;li&gt;You have experience of software projects.&lt;/li&gt;
&lt;li&gt;You are a quick and self-directed learner. We provide close support and mentorship, but you will have ownership over the design, plan, and implementation of what you build. &lt;/li&gt;
&lt;li&gt;You value, seek out, and foster diversity. We are a global team from many diverse backgrounds, with different experiences and perspectives. To complement this team, you will welcome ideas that are different from your own and be skilled at finding and building from common ground.&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;You are currently enrolled in a bachelor’s or master’s degree program in Computer Science, Software Engineering, or a similar technical major, from an Australian or New Zealand University.&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;eop&quot;&gt;You are an Australian or New Zealand citizen, an Australian permanent resident, or have full working rights with supporting documentation&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Your graduation date is between May 2027 and March 2028&lt;/strong&gt;.&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;You must be available to begin a full-time position with The Trade Desk Australia if offered a return job opportunity.&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;You can complete a 12-week internship at our Sydney office during Australia Summer 2026 (Tentative Start Date: 30 Nov 2026, Monday)&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&amp;nbsp;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot; data-ccp-charstyle-defn=&quot;{&amp;quot;ObjectId&amp;quot;:&amp;quot;c641e779-56bc-4e6c-a8e2-18ec74ca2a29|189&amp;quot;,&amp;quot;ClassId&amp;quot;:1073872969,&amp;quot;Properties&amp;quot;:[201342447,&amp;quot;5&amp;quot;,201342448,&amp;quot;3&amp;quot;,469777841,&amp;quot;Akkurat&amp;quot;,469777842,&amp;quot;&amp;quot;,469777843,&amp;quot;ＭＳ 明朝&amp;quot;,469777844,&amp;quot;Akkurat&amp;quot;,469769226,&amp;quot;Akkurat,ＭＳ 明朝&amp;quot;,268442635,&amp;quot;24&amp;quot;,469775450,&amp;quot;normaltextrun&amp;quot;,201340122,&amp;quot;1&amp;quot;,134233614,&amp;quot;true&amp;quot;,469778129,&amp;quot;normaltextrun&amp;quot;,335572020,&amp;quot;1&amp;quot;,469778324,&amp;quot;Default Paragraph Font&amp;quot;]}&quot;&gt;This is a right opportunity for you &lt;/span&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;i&lt;/span&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;f you are &lt;/span&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;looking for&lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;eop&quot; data-ccp-charstyle-defn=&quot;{&amp;quot;ObjectId&amp;quot;:&amp;quot;c641e779-56bc-4e6c-a8e2-18ec74ca2a29|190&amp;quot;,&amp;quot;ClassId&amp;quot;:1073872969,&amp;quot;Properties&amp;quot;:[201342447,&amp;quot;5&amp;quot;,201342448,&amp;quot;3&amp;quot;,469777841,&amp;quot;Akkurat&amp;quot;,469777842,&amp;quot;&amp;quot;,469777843,&amp;quot;ＭＳ 明朝&amp;quot;,469777844,&amp;quot;Akkurat&amp;quot;,469769226,&amp;quot;Akkurat,ＭＳ 明朝&amp;quot;,268442635,&amp;quot;24&amp;quot;,469775450,&amp;quot;eop&amp;quot;,201340122,&amp;quot;1&amp;quot;,134233614,&amp;quot;true&amp;quot;,469778129,&amp;quot;eop&amp;quot;,335572020,&amp;quot;1&amp;quot;,469778324,&amp;quot;Default Paragraph Font&amp;quot;]}&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span data-ccp-props=&quot;{&amp;quot;134233117&amp;quot;:false,&amp;quot;134233118&amp;quot;:false,&amp;quot;335559738&amp;quot;:0,&amp;quot;335559739&amp;quot;:0}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Work at a Global Technology Company with a Mission&lt;/strong&gt;: Be part of a company dedicated to making the Internet better for everyone—consumers, content owners, and marketers—by contributing to meaningful and impactful projects that transform how advertising is bought and sold.&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Innovate and Solve Unsolved Problems&lt;/strong&gt;: Tackle challenges that don’t have predefined solutions, where you take ownership and are responsible for delivering impactful outcomes.&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Engage in Unique, Large-Scale Challenges&lt;/strong&gt;: Work with cutting-edge technology on a platform that handles over 11 million requests per second, processing more queries than the combined searches on Google, tweets on Twitter, and snaps on Snapchat.&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Be Part of an Award-Winning Culture&lt;/strong&gt;: Join a collaborative, trust-driven workplace that values empathy, collaboration, and ownership—a culture built to support your growth.&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Explore Future SWE Full Time Opportunities&lt;/strong&gt;: Outstanding interns may have the chance to return to the same office and team for future SWE full-time position.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;eop&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;134233117&amp;quot;:false,&amp;quot;134233118&amp;quot;:false,&amp;quot;335559738&amp;quot;:0,&amp;quot;335559739&amp;quot;:0}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;What and how you can contribute is &lt;/span&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;what’s&lt;/span&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt; important to us. Our consideration is&lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;eop&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;not limited by the kind of education you have or the specific technologies you have experience with. We care about having good people to pitch in. Our culture is creative, energetic, and collaborative. Those &lt;/span&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;aren’t&lt;/span&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt; perks – those are just the way we do business.&lt;/span&gt;&lt;/span&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;eop&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;134233117&amp;quot;:false,&amp;quot;134233118&amp;quot;:false,&amp;quot;335559738&amp;quot;:0,&amp;quot;335559739&amp;quot;:0}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;eop&quot;&gt; &lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;134233117&amp;quot;:false,&amp;quot;134233118&amp;quot;:false,&amp;quot;335559738&amp;quot;:0,&amp;quot;335559739&amp;quot;:0}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;If this sounds like you, we welcome your application and invite you to find out why The Trade Desk was named a &lt;/span&gt;&lt;/span&gt;&lt;a href=&quot;https://www.thetradedesk.com/press-releases/the-trade-desk-named-a-best-medium-workplace-by-great-place-to-work-and-fortune-for-four-consecutive-years&quot;&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt;Best Medium Workplace by Great Place to Work® and FORTUNE&lt;/span&gt;&lt;/span&gt;&lt;/a&gt;&lt;span data-contrast=&quot;auto&quot;&gt;&lt;span data-ccp-charstyle=&quot;normaltextrun&quot;&gt; as a Best Workplace for diversity and top technology companies.&lt;/span&gt;&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;134233117&amp;quot;:false,&amp;quot;134233118&amp;quot;:false,&amp;quot;335559738&amp;quot;:0,&amp;quot;335559739&amp;quot;:0}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&amp;nbsp;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;The Trade Desk does not accept unsolicited resumes from search firm recruiters. Fees will not be paid in the event a candidate submitted by a recruiter without an agreement in place is hired; such resumes will be deemed the sole property of The Trade Desk. The Trade Desk is an equal opportunity employer. All aspects of employment will be based on merit, competence, performance, and business needs. We do not discriminate on the basis of race, color, religion, marital status, age, national origin, ancestry, physical or mental disability, medical condition, pregnancy, genetic information, gender, sexual orientation, gender identity or expression, veteran status, or any other status protected under federal, state, or local law.&lt;/em&gt;&lt;/p&gt;&lt;div class=&quot;content-conclusion&quot;&gt;&lt;p&gt;&lt;/p&gt;
&lt;p&gt;As an Equal Opportunity Employer, The Trade Desk is committed to creating an inclusive hiring experience where everyone has the opportunity to thrive.&lt;/p&gt;
&lt;p&gt;Please reach out to us at&amp;nbsp;&lt;a href=&quot;mailto:accommodations@thetradedesk.com&quot; target=&quot;_blank&quot;&gt;accommodations@​thetradedesk.​com&lt;/a&gt;&amp;nbsp;to request an accommodation or discuss any accessibility needs you may require to access our Company Website or navigate any part of the hiring process.&amp;nbsp;&lt;/p&gt;
&lt;p&gt;When you contact us, please include your preferred contact details and specify the nature of your accommodation request or questions. Any information you share will be handled confidentially and will not impact our hiring decisions.&lt;/p&gt;
&lt;p&gt;&lt;/p&gt;&lt;/div&gt;
